module RefModule(
  input [7:0] A,
  input [7:0] B,
  input operation,
  input reset,
  output reg [7:0] C
);integer unused_result;

  always @(*) begin
    if (reset) begin
      C <= 8'b0;
    end else if (operation) begin
      unused_result = A - B;
      C <= unused_result;
    end else begin
      unused_result = A + B;
      C <= unused_result;
    end
  end

endmodule
